package scraper

import (
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"
	"unicode"

	"golang.org/x/net/html"
	"golang.org/x/net/html/atom"
)

// Result is the structured output of a scrape.
type Result struct {
	URL           string   `json:"url"`
	Title         string   `json:"title"`
	Description   string   `json:"description"`
	Headings      []string `json:"headings,omitempty"`
	Content       string   `json:"content"`
	SocialProof   []string `json:"social_proof,omitempty"`
	Links         []Link   `json:"links,omitempty"`
	RawSizeBytes  int      `json:"raw_size_bytes"`
	CleanSizeBytes int     `json:"clean_size_bytes"`
	TokenEstimate int      `json:"token_estimate"`
}

// Link is a named URL extracted from the page.
type Link struct {
	Text string `json:"text"`
	Href string `json:"href"`
}

// skipTags are HTML elements whose text content we discard entirely.
var skipTags = map[atom.Atom]bool{
	atom.Script:   true,
	atom.Style:    true,
	atom.Noscript: true,
	atom.Iframe:   true,
	atom.Svg:      true,
	atom.Path:     true,
}

// Scrape fetches url and returns structured, compact content.
// maxContentChars limits the plain-text content field (0 = 4000 chars default).
func Scrape(url string, maxContentChars int) (*Result, error) {
	if maxContentChars <= 0 {
		maxContentChars = 4000
	}

	client := &http.Client{Timeout: 15 * time.Second}
	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; NurgeBot/1.0)")
	req.Header.Set("Accept", "text/html,application/xhtml+xml")

	resp, err := client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetching %s: %w", url, err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("HTTP %d for %s", resp.StatusCode, url)
	}

	// Read the full body to measure raw size.
	raw, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading body: %w", err)
	}

	doc, err := html.Parse(strings.NewReader(string(raw)))
	if err != nil {
		return nil, fmt.Errorf("parsing HTML: %w", err)
	}

	r := &Result{
		URL:          url,
		RawSizeBytes: len(raw),
	}

	var textParts []string
	extract(doc, r, &textParts)

	full := collapseWhitespace(strings.Join(textParts, " "))
	if len(full) > maxContentChars {
		full = full[:maxContentChars] + "…"
	}
	r.Content = full
	r.CleanSizeBytes = len(r.Content)
	// Rough token estimate: ~4 chars per token for English.
	r.TokenEstimate = len(r.Content)/4 + countJSON(r)

	return r, nil
}

// extract walks the HTML tree, pulling out title, meta, headings, links, and text.
func extract(n *html.Node, r *Result, parts *[]string) {
	if n.Type == html.ElementNode {
		// Skip invisible elements.
		if skipTags[n.DataAtom] {
			return
		}

		switch n.DataAtom {
		case atom.Title:
			r.Title = textContent(n)
			return
		case atom.Meta:
			handleMeta(n, r)
			return
		case atom.H1, atom.H2, atom.H3:
			txt := strings.TrimSpace(textContent(n))
			if txt != "" {
				r.Headings = append(r.Headings, txt)
				*parts = append(*parts, txt)
			}
			return
		case atom.A:
			link := extractLink(n)
			if link != nil {
				r.Links = append(r.Links, *link)
			}
		}
	}

	if n.Type == html.TextNode {
		t := strings.TrimSpace(n.Data)
		if t != "" {
			*parts = append(*parts, t)
			maybeSocialProof(t, r)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		extract(c, r, parts)
	}
}

func handleMeta(n *html.Node, r *Result) {
	var name, property, content string
	for _, a := range n.Attr {
		switch a.Key {
		case "name":
			name = strings.ToLower(a.Val)
		case "property":
			property = strings.ToLower(a.Val)
		case "content":
			content = a.Val
		}
	}
	if content == "" {
		return
	}
	if name == "description" || property == "og:description" {
		if r.Description == "" || property == "og:description" {
			r.Description = content
		}
	}
}

func extractLink(n *html.Node) *Link {
	var href string
	for _, a := range n.Attr {
		if a.Key == "href" {
			href = a.Val
			break
		}
	}
	if href == "" || strings.HasPrefix(href, "#") || strings.HasPrefix(href, "javascript:") {
		return nil
	}
	text := strings.TrimSpace(textContent(n))
	if text == "" || len(text) > 100 {
		return nil
	}
	return &Link{Text: text, Href: href}
}

func textContent(n *html.Node) string {
	var sb strings.Builder
	var walk func(*html.Node)
	walk = func(n *html.Node) {
		if n.Type == html.TextNode {
			sb.WriteString(n.Data)
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			walk(c)
		}
	}
	walk(n)
	return sb.String()
}

// maybeSocialProof detects text that looks like social proof.
var proofSignals = []string{
	"customer", "trusted by", "used by", "companies use",
	"fortune 500", "enterprise", "case study", "testimonial",
	"% increase", "% decrease", "% reduction", "% growth",
	"roi", "revenue", "saved", "generated",
}

func maybeSocialProof(text string, r *Result) {
	lower := strings.ToLower(text)
	for _, signal := range proofSignals {
		if strings.Contains(lower, signal) {
			trimmed := strings.TrimSpace(text)
			if len(trimmed) > 20 && len(trimmed) < 300 {
				r.SocialProof = append(r.SocialProof, trimmed)
			}
			return
		}
	}
}

func collapseWhitespace(s string) string {
	var sb strings.Builder
	prevSpace := false
	for _, r := range s {
		if unicode.IsSpace(r) {
			if !prevSpace {
				sb.WriteRune(' ')
				prevSpace = true
			}
		} else {
			sb.WriteRune(r)
			prevSpace = false
		}
	}
	return strings.TrimSpace(sb.String())
}

// countJSON estimates extra tokens from the structured JSON fields.
func countJSON(r *Result) int {
	extra := len(r.Title)/4 + len(r.Description)/4
	for _, h := range r.Headings {
		extra += len(h) / 4
	}
	for _, p := range r.SocialProof {
		extra += len(p) / 4
	}
	for _, l := range r.Links {
		extra += (len(l.Text) + len(l.Href)) / 4
	}
	extra += 50 // JSON keys overhead
	return extra
}

