package cmd

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/email"
)

var emailsFormat string

var emailsCmd = &cobra.Command{
	Use:   "emails",
	Short: "Manage synced emails",
}

var emailsListCmd = &cobra.Command{
	Use:   "list",
	Short: "List synced emails",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		class, _ := cmd.Flags().GetString("class")
		limit, _ := cmd.Flags().GetInt("limit")

		list, err := email.List(d, email.ListOptions{Class: class, Limit: limit})
		if err != nil {
			return err
		}

		if emailsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(list)
		}

		for _, e := range list {
			date := e.Date
			if len(date) >= 10 {
				date = date[:10]
			}
			fmt.Printf("  [%s] %s → %s\n    %s\n", e.Class, date, e.Subject, e.Snippet)
		}
		return nil
	},
}

var emailsStatsCmd = &cobra.Command{
	Use:   "stats",
	Short: "Show email statistics",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		stats, err := email.Stats(d)
		if err != nil {
			return err
		}

		if emailsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(stats)
		}

		fmt.Printf("  Total emails: %d\n", stats.Total)
		fmt.Printf("  Unclassified: %d\n", stats.Unclassified)
		fmt.Printf("  Date range: %s to %s\n", stats.DateRange.Earliest, stats.DateRange.Latest)
		fmt.Println("  By class:")
		for class, count := range stats.ByClass {
			fmt.Printf("    %s: %d\n", class, count)
		}
		return nil
	},
}

var emailsClassifyCmd = &cobra.Command{
	Use:   "classify",
	Short: "Update email classifications from stdin",
	Long:  "Reads JSON array from stdin: [{\"id\": \"msg-123\", \"class\": \"outbound\", \"confidence\": 0.95}]",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		var updates []email.ClassifyUpdate
		if err := json.NewDecoder(os.Stdin).Decode(&updates); err != nil {
			return fmt.Errorf("parsing stdin: %w", err)
		}

		count, err := email.Classify(d, updates)
		if err != nil {
			return err
		}

		fmt.Printf("  ✓ Classified %d emails\n", count)
		return nil
	},
}

var emailsCheckCmd = &cobra.Command{
	Use:   "check",
	Short: "Check email sending health",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		health, err := email.Check(d)
		if err != nil {
			return err
		}

		if emailsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(health)
		}

		fmt.Printf("  Emails/day (last 7d): %.1f\n", health.DailyAvg7d)
		fmt.Printf("  Emails/day (last 30d): %.1f\n", health.DailyAvg30d)
		fmt.Printf("  Unique recipients (last 30d): %d\n", health.UniqueRecipients30d)
		return nil
	},
}

func init() {
	emailsCmd.PersistentFlags().StringVar(&emailsFormat, "format", "", "Output format (json)")
	emailsListCmd.Flags().String("class", "", "Filter by classification")
	emailsListCmd.Flags().Int("limit", 0, "Max results")
	emailsCmd.AddCommand(emailsListCmd)
	emailsCmd.AddCommand(emailsStatsCmd)
	emailsCmd.AddCommand(emailsClassifyCmd)
	emailsCmd.AddCommand(emailsCheckCmd)
	rootCmd.AddCommand(emailsCmd)
}

package email

import (
	"database/sql"
	"fmt"
)

type Email struct {
	ID              string  `json:"id"`
	ThreadID        string  `json:"thread_id"`
	Subject         string  `json:"subject"`
	FromEmail       string  `json:"from_email"`
	ToEmails        string  `json:"to_emails"`
	CcEmails        string  `json:"cc_emails"`
	Date            string  `json:"date"`
	Snippet         string  `json:"snippet"`
	Class           string  `json:"class"`
	ClassConfidence float64 `json:"class_confidence"`
	ClassifiedBy    string  `json:"classified_by"`
}

type ListOptions struct {
	Class  string
	Limit  int
	Offset int
}

func List(d *sql.DB, opts ListOptions) ([]Email, error) {
	query := "SELECT id, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, class, class_confidence, classified_by FROM emails"
	var args []any

	if opts.Class != "" {
		query += " WHERE class = ?"
		args = append(args, opts.Class)
	}

	query += " ORDER BY date DESC"

	if opts.Limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
		if opts.Offset > 0 {
			query += fmt.Sprintf(" OFFSET %d", opts.Offset)
		}
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var emailList []Email
	for rows.Next() {
		var e Email
		var subject, ccEmails, snippet, classifiedBy sql.NullString
		if err := rows.Scan(&e.ID, &e.ThreadID, &subject, &e.FromEmail, &e.ToEmails, &ccEmails, &e.Date, &snippet, &e.Class, &e.ClassConfidence, &classifiedBy); err != nil {
			return nil, err
		}
		e.Subject = subject.String
		e.CcEmails = ccEmails.String
		e.Snippet = snippet.String
		e.ClassifiedBy = classifiedBy.String
		emailList = append(emailList, e)
	}
	return emailList, rows.Err()
}

