package email

import "database/sql"

type ClassifyUpdate struct {
	ID           string  `json:"id"`
	Class        string  `json:"class"`
	Confidence   float64 `json:"confidence"`
	ClassifiedBy string  `json:"classified_by"`
}

func Classify(d *sql.DB, updates []ClassifyUpdate) (int, error) {
	tx, err := d.Begin()
	if err != nil {
		return 0, err
	}
	defer tx.Rollback()

	stmt, err := tx.Prepare("UPDATE emails SET class = ?, class_confidence = ?, classified_by = ? WHERE id = ?")
	if err != nil {
		return 0, err
	}
	defer stmt.Close()

	count := 0
	for _, u := range updates {
		if u.ClassifiedBy == "" {
			u.ClassifiedBy = "claude"
		}
		res, err := stmt.Exec(u.Class, u.Confidence, u.ClassifiedBy, u.ID)
		if err != nil {
			return count, err
		}
		n, _ := res.RowsAffected()
		count += int(n)
	}

	return count, tx.Commit()
}

