package email

import (
	"database/sql"
	"encoding/json"
	"strings"
)

// AutoClassifyResult reports what the heuristic classifier did.
type AutoClassifyResult struct {
	Total        int            `json:"total"`
	Classified   int            `json:"classified"`
	Remaining    int            `json:"remaining"`
	ByClass      map[string]int `json:"by_class"`
	SenderDomain string         `json:"-"` // caller's domain, used internally
}

// ClassifyAuto applies deterministic heuristics to unclassified emails.
// senderDomain is the user's sending domain (e.g. "acme.com").
// Returns a summary of what was classified and how many remain for Claude.
func ClassifyAuto(d *sql.DB, senderDomain string) (*AutoClassifyResult, error) {
	senderDomain = strings.ToLower(strings.TrimSpace(senderDomain))

	// Fetch all unclassified emails.
	rows, err := d.Query(`SELECT id, from_email, to_emails, subject, snippet FROM emails WHERE class = 'unclassified'`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	type candidate struct {
		id      string
		from    string
		to      string // JSON array
		subject string
		snippet string
	}

	var candidates []candidate
	for rows.Next() {
		var c candidate
		var subj, snip sql.NullString
		if err := rows.Scan(&c.id, &c.from, &c.to, &subj, &snip); err != nil {
			return nil, err
		}
		c.subject = subj.String
		c.snippet = snip.String
		candidates = append(candidates, c)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}

	// Classify with heuristics.
	var updates []ClassifyUpdate
	result := &AutoClassifyResult{
		Total:   len(candidates),
		ByClass: make(map[string]int),
	}

	for _, c := range candidates {
		class := classifyHeuristic(c.from, c.to, c.subject, c.snippet, senderDomain)
		if class == "" {
			continue // ambiguous — leave for Claude
		}
		updates = append(updates, ClassifyUpdate{
			ID:           c.id,
			Class:        class,
			Confidence:   0.85,
			ClassifiedBy: "auto",
		})
		result.ByClass[class]++
	}

	// Batch update in one transaction.
	if len(updates) > 0 {
		if _, err := Classify(d, updates); err != nil {
			return nil, err
		}
	}

	result.Classified = len(updates)
	result.Remaining = result.Total - result.Classified
	return result, nil
}

func classifyHeuristic(from, toJSON, subject, snippet, senderDomain string) string {
	fromLower := strings.ToLower(from)
	subjLower := strings.ToLower(subject)
	snipLower := strings.ToLower(snippet)

	// Parse recipient list.
	var recipients []string
	_ = json.Unmarshal([]byte(toJSON), &recipients)

	// --- Transactional signals ---
	transactionalPrefixes := []string{
		"noreply@", "no-reply@", "donotreply@", "do-not-reply@",
		"mailer-daemon@", "postmaster@", "notifications@", "notify@",
		"support@", "billing@", "receipts@", "invoice@",
	}
	for _, prefix := range transactionalPrefixes {
		if strings.HasPrefix(fromLower, prefix) {
			return "transactional"
		}
	}
	// Transactional subjects.
	transactionalSubjects := []string{
		"password reset", "verify your email", "confirm your",
		"your receipt", "your invoice", "your order", "payment confirmation",
		"subscription", "account activation", "welcome to",
	}
	for _, sig := range transactionalSubjects {
		if strings.Contains(subjLower, sig) {
			return "transactional"
		}
	}

	// --- Internal signals ---
	// All recipients share the same domain as sender.
	if senderDomain != "" && len(recipients) > 0 {
		allInternal := true
		for _, r := range recipients {
			if !strings.HasSuffix(strings.ToLower(r), "@"+senderDomain) {
				allInternal = false
				break
			}
		}
		if allInternal {
			return "internal"
		}
	}

	// --- Newsletter signals ---
	newsletterSubjects := []string{
		"newsletter", "digest", "weekly update", "monthly update",
		"unsubscribe", "weekly roundup",
	}
	for _, sig := range newsletterSubjects {
		if strings.Contains(subjLower, sig) || strings.Contains(snipLower, sig) {
			return "newsletter"
		}
	}

	// --- Personal signals ---
	// Single recipient, personal domain, short/casual subject.
	personalDomains := map[string]bool{
		"gmail.com": true, "yahoo.com": true, "hotmail.com": true,
		"outlook.com": true, "icloud.com": true, "aol.com": true,
		"protonmail.com": true, "me.com": true, "live.com": true,
	}
	if len(recipients) == 1 {
		parts := strings.SplitN(recipients[0], "@", 2)
		if len(parts) == 2 && personalDomains[strings.ToLower(parts[1])] {
			// Sender is also from a personal domain → personal.
			fromParts := strings.SplitN(from, "@", 2)
			if len(fromParts) == 2 && personalDomains[strings.ToLower(fromParts[1])] {
				return "personal"
			}
		}
	}

	// No confident match — leave for Claude.
	return ""
}

