type CompactEmail struct {
	ID      string `json:"id"`
	Subject string `json:"subject"`
	From    string `json:"from"`
	Snippet string `json:"snippet"`
}

// ListCompact returns emails with minimal fields for context-efficient AI consumption.
func ListCompact(d *sql.DB, opts ListOptions) ([]CompactEmail, error) {
	query := "SELECT id, subject, from_email, snippet FROM emails"
	var args []any

	if opts.Class != "" {
		query += " WHERE class = ?"
		args = append(args, opts.Class)
	}

	query += " ORDER BY date DESC"

	if opts.Limit > 0 {
		query += fmt.Sprintf(" LIMIT %d", opts.Limit)
		if opts.Offset > 0 {
			query += fmt.Sprintf(" OFFSET %d", opts.Offset)
		}
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var list []CompactEmail
	for rows.Next() {
		var e CompactEmail
		var subj, snip sql.NullString
		if err := rows.Scan(&e.ID, &subj, &e.From, &snip); err != nil {
			return nil, err
		}
		e.Subject = subj.String
		e.Snippet = snip.String
		list = append(list, e)
	}
	return list, rows.Err()
}

