package cmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/project"
)

var (
	buildVersion = "dev"
	buildCommit  = "none"
	buildDate    = "unknown"
)

var convexSiteURL = ""

// SetVersion sets the build version info from ldflags.
func SetVersion(version, commit, date string) {
	buildVersion = version
	buildCommit = commit
	buildDate = date
}

// SetConvexURL sets the Convex deployment URL from ldflags.
func SetConvexURL(url string) {
	convexSiteURL = url
}

// GetConvexURL returns the Convex site URL, allowing env var override for development.
func GetConvexURL() string {
	if env := os.Getenv("NURGE_CONVEX_URL"); env != "" {
		return env
	}
	return convexSiteURL
}

// GetDashboardURL returns the dashboard URL, allowing env var override for development.
func GetDashboardURL() string {
	if env := os.Getenv("NURGE_DASHBOARD_URL"); env != "" {
		return env
	}
	return "https://app.nurge.sh"
}

var (
	initForce     bool
	initSkipHooks bool
	initVerbose   bool
)

var rootCmd = &cobra.Command{
	Use:   "nurge [directory]",
	Short: "nurge — outbound that learns",
	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
	RunE:  runInit,
}

var versionCmd = &cobra.Command{
	Use:         "version",
	Short:       "Print the version of nurge",
	Annotations: map[string]string{"skipAuth": "true"},
	Run: func(cmd *cobra.Command, args []string) {
		fmt.Printf("nurge %s (commit: %s, built: %s)\n", buildVersion, buildCommit, buildDate)
	},
}

// runInit is the shared init logic used by both the root command and the hidden init alias.
func runInit(cmd *cobra.Command, args []string) error {
	dirCreated := ""

	if len(args) == 1 {
		dir := args[0]
		if err := os.MkdirAll(dir, 0755); err != nil {
			return fmt.Errorf("failed to create directory %s: %w", dir, err)
		}
		abs, err := filepath.Abs(dir)
		if err != nil {
			return err
		}
		if err := os.Chdir(abs); err != nil {
			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
		}
		dirCreated = dir
	} else if !initForce {
		// No directory arg: only init if current dir is empty or already initialized
		empty, _ := project.IsDirEmpty(".")
		alreadyInit := project.IsNurgeProject(".")
		if !empty && !alreadyInit {
			return cmd.Help()
		}
	}

	// Check if current directory is non-empty (unless --force)
	if !initForce {
		empty, err := project.IsDirEmpty(".")
		if err != nil {
			return err
		}
		if !empty && !project.IsNurgeProject(".") {
			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
		}
	}

	opts := project.Options{
		SkipHooks: initSkipHooks,
		Force:     initForce,
		Verbose:   initVerbose,
	}
	if err := project.Run(opts); err != nil {
		return err
	}

	if dirCreated != "" {
		fmt.Println()
		fmt.Printf("  Now run: cd %s\n", dirCreated)
		fmt.Println()
	}

	return nil
}

// shouldSkipAuth walks the command tree to check if any command in the
// chain has the skipAuth annotation. This handles cases like
// "nurge account login" where account has skipAuth.
func shouldSkipAuth(cmd *cobra.Command) bool {
	for c := cmd; c != nil; c = c.Parent() {
		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
			return true
		}
	}
	return false
}

func init() {
	rootCmd.AddCommand(versionCmd)

	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")

	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
		// Root command (init) skips auth — it's the first thing a user runs
		if cmd == rootCmd ||
			shouldSkipAuth(cmd) ||
			cmd.Name() == "help" ||
			cmd.Name() == "completion" {
			return nil
		}
		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
		return err
	}
}

// isKnownCommand checks if name matches any registered subcommand.
func isKnownCommand(name string) bool {
	for _, c := range rootCmd.Commands() {
		if c.Name() == name {
			return true
		}
		for _, alias := range c.Aliases {
			if alias == name {
				return true
			}
		}
	}
	return name == "help" || name == "completion"
}

func Execute() error {
