package cmd

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/metrics"
)

var metricsFormat string

var metricsCmd = &cobra.Command{
	Use:         "metrics",
	Short:       "Show context token usage metrics",
	Long:        "Track how many tokens each CLI command contributes to Claude's context window.",
	Annotations: map[string]string{"skipAuth": "true"},
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := metrics.EnsureTable(d); err != nil {
			return err
		}

		sid := metrics.SessionID()
		summary, err := metrics.Summary(d, sid)
		if err != nil {
			return err
		}

		if metricsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(summary)
		}

		if summary.CommandCount == 0 {
			fmt.Println("  No metrics recorded for current session.")
			return nil
		}

		fmt.Printf("  Session: %s\n", sid)
		fmt.Printf("  Commands: %d  |  Total: %s (~%d tokens)\n\n",
			summary.CommandCount, metrics.FormatBytes(summary.TotalBytes), summary.TotalTokens)
		fmt.Printf("  %-30s %6s %10s %8s\n", "COMMAND", "CALLS", "BYTES", "TOKENS")
		fmt.Printf("  %-30s %6s %10s %8s\n", "-------", "-----", "-----", "------")
		for _, cs := range summary.ByCommand {
			fmt.Printf("  %-30s %6d %10s %8d\n",
				cs.Command, cs.Calls, metrics.FormatBytes(cs.TotalBytes), cs.TotalTokens)
		}
		return nil
	},
}

var metricsHistoryCmd = &cobra.Command{
	Use:   "history",
	Short: "Show per-session token usage over time",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := metrics.EnsureTable(d); err != nil {
			return err
		}

		limit, _ := cmd.Flags().GetInt("limit")
		sessions, err := metrics.SessionHistory(d, limit)
		if err != nil {
			return err
		}

		if metricsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(sessions)
		}

		if len(sessions) == 0 {
			fmt.Println("  No metrics recorded yet.")
			return nil
		}

		fmt.Printf("  %-22s %6s %10s %8s\n", "SESSION", "CMDS", "BYTES", "TOKENS")
		fmt.Printf("  %-22s %6s %10s %8s\n", "-------", "----", "-----", "------")
		for _, s := range sessions {
			fmt.Printf("  %-22s %6d %10s %8d\n",
				s.SessionID, s.CommandCount, metrics.FormatBytes(s.TotalBytes), s.TotalTokens)
		}
		return nil
	},
}

var metricsBudgetCmd = &cobra.Command{
	Use:   "budget",
	Short: "Show estimated context budget for current session",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := metrics.EnsureTable(d); err != nil {
			return err
		}

		budget, err := metrics.EstimateBudget(d, metrics.SessionID())
		if err != nil {
			return err
		}

		if metricsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(budget)
		}

		fmt.Println("  Context Budget Estimate")
		fmt.Println("  -----------------------")
		fmt.Printf("  CLI output:        %6d tokens  (measured)\n", budget.CLITokens)
		fmt.Printf("  Skill file reads:  %6d tokens  (estimated)\n", budget.EstSkillReads)
		fmt.Printf("  Conversation:      %6d tokens  (estimated)\n", budget.EstConversation)
		fmt.Printf("  ─────────────────────────────────\n")
		fmt.Printf("  Total:             %6d tokens\n", budget.EstTotal)
		fmt.Printf("  Context limit:     %6d tokens\n", budget.ContextLimit)
		fmt.Printf("  Usage:             %5.1f%%\n", budget.UsagePercent)
		return nil
	},
}

var metricsRecentCmd = &cobra.Command{
	Use:   "recent",
	Short: "Show recent individual command metrics",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := metrics.EnsureTable(d); err != nil {
			return err
		}

		limit, _ := cmd.Flags().GetInt("limit")
		entries, err := metrics.Recent(d, limit)
		if err != nil {
			return err
		}

		if metricsFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(entries)
		}

		if len(entries) == 0 {
			fmt.Println("  No metrics recorded yet.")
			return nil
		}

		fmt.Printf("  %-20s %-30s %10s %8s\n", "TIME", "COMMAND", "BYTES", "TOKENS")
		fmt.Printf("  %-20s %-30s %10s %8s\n", "----", "-------", "-----", "------")
		for _, e := range entries {
			t := e.CreatedAt
			if len(t) > 19 {
				t = t[:19]
			}
			fmt.Printf("  %-20s %-30s %10s %8d\n",
				t, e.Command, metrics.FormatBytes(e.OutputBytes), e.TokenEstimate)
		}
		return nil
	},
}

func init() {
	metricsCmd.PersistentFlags().StringVar(&metricsFormat, "format", "", "Output format (json)")
	metricsHistoryCmd.Flags().Int("limit", 20, "Max sessions to show")
	metricsRecentCmd.Flags().Int("limit", 50, "Max entries to show")

	metricsCmd.AddCommand(metricsHistoryCmd)
	metricsCmd.AddCommand(metricsBudgetCmd)
	metricsCmd.AddCommand(metricsRecentCmd)
	rootCmd.AddCommand(metricsCmd)
}

