  1→package sync
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→	"time"
  9→
 10→	"github.com/usenurge/nurgesh/internal/account"
 11→)
 12→
 13→// executionTables are tables where Convex is authoritative.
 14→// Pull direction: Convex → SQLite.
 15→var executionTables = []string{
 16→	"emails",
 17→	"mailboxes",
 18→	"mailbox_send_events",
 19→	"sequence_enrollments",
 20→	"follow_up_tasks",
 21→	"suppressions",
 22→	"reply_events",
 23→	"sequence_drafts",
 24→}
 25→
 26→// localTables are tables where SQLite is authoritative.
 27→// Push direction: SQLite → Convex.
 28→var localTables = []string{
 29→	"contacts",
 30→	"learnings",
 31→	"skill_versions",
 32→	"deals",
 33→}
 34→
 35→const batchSize = 500
 36→
 37→// SyncState tracks the last sync position per direction.
 38→type SyncState struct {
 39→	LastPullVersion int64  `json:"last_pull_version"`
 40→	LastPushAt      string `json:"last_push_at"`
 41→}
 42→
 43→// Engine handles bidirectional sync between SQLite and Convex.
 44→type Engine struct {
 45→	db     *sql.DB
 46→	client *account.ConvexClient
 47→	token  string
 48→}
 49→
 50→// NewEngine creates a sync engine.
 51→func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
 52→	return &Engine{db: db, client: client, token: token}
 53→}
 54→
 55→// PullResult contains stats from a pull operation.
 56→type PullResult struct {
 57→	PreviousVersion int64
 58→	CurrentVersion  int64
 59→	TablesUpdated   int
 60→	RowsUpserted    int
 61→	TableCounts     map[string]int
 62→}
 63→
 64→// PushResult contains stats from a push operation.
 65→type PushResult struct {
 66→	TablesScanned int
 67→	RowsPushed    int
 68→}
 69→
 70→// SyncResult contains stats from a full sync (pull + push).
 71→type SyncResult struct {
 72→	Pull PullResult
 73→	Push PushResult
 74→}
 75→
 76→// Sync performs a full sync: pull execution state, then push local state.
 77→func (e *Engine) Sync() (*SyncResult, error) {
 78→	pullResult, err := e.Pull()
 79→	if err != nil {
 80→		return nil, fmt.Errorf("pull failed: %w", err)
 81→	}
 82→
 83→	pushResult, err := e.Push()
 84→	if err != nil {
 85→		return nil, fmt.Errorf("push failed: %w", err)
 86→	}
 87→
 88→	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
 89→}
 90→
 91→// Pull fetches execution state from Convex and upserts into SQLite.
 92→func (e *Engine) Pull() (*PullResult, error) {
 93→	state, err := e.loadSyncState()
 94→	if err != nil {
 95→		return nil, fmt.Errorf("loading sync state: %w", err)
 96→	}
 97→	previousVersion := state.LastPullVersion
 98→
 99→	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
100→	if err != nil {
101→		return nil, fmt.Errorf("pulling from Convex: %w", err)
102→	}
103→
104→	result := &PullResult{
105→		PreviousVersion: previousVersion,
106→		CurrentVersion:  previousVersion,
107→		TableCounts:     make(map[string]int),
108→	}
109→	tablesUpdated := map[string]bool{}
110→
111→	for _, row := range resp.Rows {
112→		if row.Table == "mailboxes" {
113→			if skip, _ := e.wouldExceedMailboxLimit(row.ID); skip {
114→				continue
115→			}
116→		}
117→		if err := e.upsertRow(row); err != nil {
118→			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
119→		}
120→		result.RowsUpserted++
121→		tablesUpdated[row.Table] = true
122→		result.TableCounts[row.Table]++
123→	}
124→	result.TablesUpdated = len(tablesUpdated)
125→
126→	if resp.SyncVersion > state.LastPullVersion {
127→		state.LastPullVersion = resp.SyncVersion
128→		result.CurrentVersion = resp.SyncVersion
129→		if err := e.saveSyncState(state); err != nil {
130→			return nil, fmt.Errorf("saving sync state: %w", err)
131→		}
132→	}
133→
134→	return result, nil
135→}
136→
137→// Push sends local state changes to Convex.
138→func (e *Engine) Push() (*PushResult, error) {
139→	state, err := e.loadSyncState()
140→	if err != nil {
141→		return nil, fmt.Errorf("loading sync state: %w", err)
142→	}
143→
144→	result := &PushResult{}
145→	var allRows []account.SyncRow
146→
147→	for _, table := range localTables {
148→		rows, err := e.changedLocalRows(table, state.LastPushAt)
149→		if err != nil {
150→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
151→		}
152→		allRows = append(allRows, rows...)
153→		result.TablesScanned++
154→	}
155→
156→	// Also push email classifications (local authority for the classification field)
157→	classRows, err := e.changedEmailClassifications()
158→	if err != nil {
159→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
160→	}
161→	allRows = append(allRows, classRows...)
162→
163→	if len(allRows) == 0 {
164→		return result, nil
165→	}
166→
167→	// Push in batches
168→	for i := 0; i < len(allRows); i += batchSize {
169→		end := i + batchSize
170→		if end > len(allRows) {
171→			end = len(allRows)
172→		}
173→		batch := allRows[i:end]
174→
175→		resp, err := e.client.PushLocalState(e.token, batch)
176→		if err != nil {
177→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
178→		}
179→
180→		// Update local sync_version from server response
181→		for id, version := range resp.Versions {
182→			for _, row := range batch {
183→				if row.ID == id {
184→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
185→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
186→					}
187→					break
188→				}
189→			}
190→		}
191→		result.RowsPushed += len(batch)
192→	}
193→
194→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
195→	if err := e.saveSyncState(state); err != nil {
196→		return nil, fmt.Errorf("saving sync state: %w", err)
197→	}
198→
199→	return result, nil
200→}
201→
202→// wouldExceedMailboxLimit returns true if inserting this mailbox ID would exceed the max.
203→// Updates to existing mailboxes are always allowed.
204→func (e *Engine) wouldExceedMailboxLimit(id string) (bool, error) {
205→	var exists bool
206→	err := e.db.QueryRow("SELECT EXISTS(SELECT 1 FROM mailboxes WHERE id = ?)", id).Scan(&exists)
207→	if err != nil {
208→		return false, err
209→	}
210→	if exists {
211→		return false, nil // update, always allowed
212→	}
213→	var count int
214→	err = e.db.QueryRow("SELECT COUNT(*) FROM mailboxes").Scan(&count)
215→	if err != nil {
216→		return false, err
217→	}
218→	return count >= 2, nil
219→}
220→
221→// upsertRow writes a Convex row into the local SQLite table.
222→func (e *Engine) upsertRow(row account.SyncRow) error {
223→	if len(row.Data) == 0 {
224→		return nil
225→	}
226→
227→	columns := []string{"id"}
228→	placeholders := []string{"?"}
229→	values := []any{row.ID}
230→	updateParts := []string{}
231→
232→	for col, val := range row.Data {
233→		columns = append(columns, col)
234→		placeholders = append(placeholders, "?")
235→		values = append(values, val)
236→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
237→	}
238→
239→	// Always set sync_version
240→	columns = append(columns, "sync_version")
241→	placeholders = append(placeholders, "?")
242→	values = append(values, row.Version)
243→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
244→
245→	query := fmt.Sprintf(
246→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
247→		row.Table,
248→		strings.Join(columns, ", "),
249→		strings.Join(placeholders, ", "),
250→		strings.Join(updateParts, ", "),
251→	)
252→
253→	_, err := e.db.Exec(query, values...)
254→	return err
255→}
