257→// changedLocalRows returns rows from a local-state table changed since lastPushAt.
258→func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
259→	var rows []account.SyncRow
260→
261→	query := fmt.Sprintf("SELECT * FROM %s", table)
262→	args := []any{}
263→	if lastPushAt != "" {
264→		query += " WHERE updated_at > ?"
265→		args = append(args, lastPushAt)
266→	}
267→
268→	sqlRows, err := e.db.Query(query, args...)
269→	if err != nil {
270→		return nil, err
271→	}
272→	defer sqlRows.Close()
273→
274→	cols, err := sqlRows.Columns()
275→	if err != nil {
276→		return nil, err
277→	}
278→
279→	for sqlRows.Next() {
280→		values := make([]any, len(cols))
281→		ptrs := make([]any, len(cols))
282→		for i := range values {
283→			ptrs[i] = &values[i]
284→		}
285→		if err := sqlRows.Scan(ptrs...); err != nil {
286→			return nil, err
287→		}
288→
289→		data := map[string]any{}
290→		var id string
291→		for i, col := range cols {
292→			if col == "id" {
293→				id = fmt.Sprintf("%v", values[i])
294→			}
295→			if col == "sync_version" {
296→				continue // don't push sync_version back
297→			}
298→			data[col] = values[i]
299→		}
300→
301→		rows = append(rows, account.SyncRow{
302→			Table: table,
303→			ID:    id,
304→			Data:  data,
305→		})
306→	}
307→
308→	return rows, sqlRows.Err()
309→}
