311→// changedEmailClassifications returns all classified emails for push.
312→// Emails lack updated_at so all are pushed each time — idempotent on Convex side.
313→func (e *Engine) changedEmailClassifications() ([]account.SyncRow, error) {
314→	sqlRows, err := e.db.Query(`SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`)
315→	if err != nil {
316→		return nil, err
317→	}
318→	defer sqlRows.Close()
319→
320→	var rows []account.SyncRow
321→	for sqlRows.Next() {
322→		var id, class, classifiedBy string
323→		var confidence float64
324→		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
325→			return nil, err
326→		}
327→
328→		rows = append(rows, account.SyncRow{
329→			Table: "emails",
330→			ID:    id,
331→			Data: map[string]any{
332→				"class":            class,
333→				"class_confidence": confidence,
334→				"classified_by":    classifiedBy,
335→			},
336→		})
337→	}
338→
339→	return rows, sqlRows.Err()
340→}
