342→// updateSyncVersion sets the sync_version for a specific row.
343→func (e *Engine) updateSyncVersion(table, id string, version int64) error {
344→	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
345→	_, err := e.db.Exec(query, version, id)
346→	return err
347→}
348→
349→const syncStateKey = "_sync_state"
350→
351→// loadSyncState reads the sync cursor from a local config-like store.
352→func (e *Engine) loadSyncState() (*SyncState, error) {
353→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
354→	var data string
355→	err := e.db.QueryRow(
356→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
357→	).Scan(&data)
358→	if err == sql.ErrNoRows {
359→		return &SyncState{}, nil
360→	}
361→	if err != nil {
362→		return nil, err
363→	}
364→
365→	var state SyncState
366→	if err := json.Unmarshal([]byte(data), &state); err != nil {
367→		return &SyncState{}, nil
368→	}
369→	return &state, nil
370→}
371→
372→// saveSyncState persists the sync cursor.
373→func (e *Engine) saveSyncState(state *SyncState) error {
374→	data, err := json.Marshal(state)
375→	if err != nil {
376→		return err
377→	}
378→
379→	_, err = e.db.Exec(`
380→		INSERT INTO connectors (id, type, sync_cursor)
381→		VALUES (?, 'sync', ?)
382→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
383→		syncStateKey, string(data),
384→	)
385→	return err
386→}
