 73→  args: {
 74→    userId: v.string(),
 75→    rows: v.array(
 76→      v.object({
 77→        table: v.string(),
 78→        id: v.string(),
 79→        data: v.any(),
 80→      })
 81→    ),
 82→  },
 83→  handler: async (ctx, args) => {
 84→    const versions: Record<string, number> = {};
 85→
 86→    // Get current max sync version
 87→    const syncState = await ctx.db
 88→      .query("syncState")
 89→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
 90→      .first();
 91→
 92→    let currentVersion = syncState?.lastSyncVersion ?? 0;
 93→
 94→    // Reverse map: snake_case → camelCase
 95→    const reverseTableMap: Record<string, string> = {};
 96→    for (const [convex, sqlite] of Object.entries(TABLE_MAP)) {
 97→      reverseTableMap[sqlite] = convex;
 98→    }
 99→
100→    for (const row of args.rows) {
101→      const convexTable = reverseTableMap[row.table] || row.table;
102→      currentVersion++;
103→
104→      // Check if row exists
105→      const existing = await ctx.db
106→        .query(convexTable as any)
107→        .withIndex("by_external_id", (q) => q.eq("externalId", row.id))
108→        .first();
109→
110→      const rowData = {
111→        ...(row.data as Record<string, any>),
112→        externalId: row.id,
113→        syncVersion: currentVersion,
114→        userId: args.userId,
115→      };
116→
117→      if (existing) {
118→        await ctx.db.patch(existing._id, rowData);
119→      } else {
120→        await ctx.db.insert(convexTable as any, rowData);
121→      }
122→
123→      versions[row.id] = currentVersion;
124→    }
125→
126→    // Update sync state
127→    if (syncState) {
128→      await ctx.db.patch(syncState._id, { lastSyncVersion: currentVersion });
129→    } else {
130→      await ctx.db.insert("syncState", {
131→        userId: args.userId,
132→        lastSyncVersion: currentVersion,
133→      });
134→    }
135→
136→    return { versions };
137→  },
138→});
