package account

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
)

// SyncRow represents a generic row for sync operations.
type SyncRow struct {
	Table   string         `json:"table"`
	ID      string         `json:"id"`
	Data    map[string]any `json:"data"`
	Version int64          `json:"version,omitempty"`
}

// PullResponse contains changed rows from Convex.
type PullResponse struct {
	Rows        []SyncRow `json:"rows"`
	SyncVersion int64     `json:"sync_version"`
}

// PushResponse contains server-assigned versions for pushed rows.
type PushResponse struct {
	Versions map[string]int64 `json:"versions"` // id → sync_version
}

// SendIntentRequest is the payload for creating a send intent on Convex.
type SendIntentRequest struct {
	Token      string         `json:"token"`
	Enrollment map[string]any `json:"enrollment"`
	Task       map[string]any `json:"task"`
	Drafts     []map[string]any `json:"drafts,omitempty"`
	SendType   string         `json:"send_type"`
	Email      map[string]any `json:"email"`
}

// SendIntentResponse is returned after Convex processes a send intent.
type SendIntentResponse struct {
	EnrollmentID string `json:"enrollment_id"`
	TaskID       string `json:"task_id"`
	SendStatus   string `json:"send_status"`
	MessageID    string `json:"message_id,omitempty"`
	ProviderID   string `json:"provider_id,omitempty"`
	Error        string `json:"error,omitempty"`
}

// MutationRequest is a generic mutation sent to Convex.
type MutationRequest struct {
	Token  string         `json:"token"`
	Action string         `json:"action"`
	Data   map[string]any `json:"data"`
}

// MutationResponse is a generic response from a Convex mutation.
type MutationResponse struct {
	OK      bool           `json:"ok"`
	Data    map[string]any `json:"data,omitempty"`
	Error   string         `json:"error,omitempty"`
	Version int64          `json:"version,omitempty"`
}

// PullExecutionState fetches execution-state rows changed since lastSyncVersion.
func (c *ConvexClient) PullExecutionState(token string, lastSyncVersion int64) (*PullResponse, error) {
	body, err := json.Marshal(map[string]any{
		"token":        token,
		"sync_version": lastSyncVersion,
	})
	if err != nil {
		return nil, fmt.Errorf("marshaling pull request: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/pull-execution-state",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling pull-execution-state: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("pull-execution-state failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result PullResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing pull response: %w", err)
	}
	return &result, nil
}

// PushLocalState pushes local-state changes to Convex.
func (c *ConvexClient) PushLocalState(token string, rows []SyncRow) (*PushResponse, error) {
	body, err := json.Marshal(map[string]any{
		"token": token,
		"rows":  rows,
	})
	if err != nil {
		return nil, fmt.Errorf("marshaling push request: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/push-local-state",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling push-local-state: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("push-local-state failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result PushResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing push response: %w", err)
	}
	return &result, nil
}

// CreateSendIntent sends a send intent to Convex for processing.
func (c *ConvexClient) CreateSendIntent(req *SendIntentRequest) (*SendIntentResponse, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("marshaling send intent: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/create-send-intent",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling create-send-intent: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("create-send-intent failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result SendIntentResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing send intent response: %w", err)
	}
	if result.Error != "" {
		return nil, fmt.Errorf("send intent rejected: %s", result.Error)
	}
	return &result, nil
}

// Mutate sends a generic mutation to Convex (stop enrollment, pause, suppress, etc.)
func (c *ConvexClient) Mutate(req *MutationRequest) (*MutationResponse, error) {
	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("marshaling mutation: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/mutate",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling mutate: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("mutate failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result MutationResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing mutation response: %w", err)
	}
	if !result.OK {
		return nil, fmt.Errorf("mutation failed: %s", result.Error)
	}
	return &result, nil
}

// RequestConnectionLink asks Convex to generate a Unipile hosted auth link.
func (c *ConvexClient) RequestConnectionLink(token, provider string) (string, error) {
	body, err := json.Marshal(map[string]string{
		"token":    token,
		"provider": provider,
	})
	if err != nil {
		return "", fmt.Errorf("marshaling connection link request: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/request-connection-link",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return "", fmt.Errorf("calling request-connection-link: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("request-connection-link failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result struct {
		URL   string `json:"url"`
		Error string `json:"error,omitempty"`
	}
	if err := json.Unmarshal(data, &result); err != nil {
		return "", fmt.Errorf("parsing response: %w", err)
	}
	if result.Error != "" {
		return "", fmt.Errorf("connection link failed: %s", result.Error)
	}
	return result.URL, nil
}

