package metrics

import (
	"database/sql"
	"fmt"
	"io"
	"os"
	"sync"
	"time"
)

// EnsureTable creates the context_metrics table if it doesn't exist.
func EnsureTable(d *sql.DB) error {
	_, err := d.Exec(`
		CREATE TABLE IF NOT EXISTS context_metrics (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			session_id TEXT NOT NULL DEFAULT '',
			command TEXT NOT NULL,
			output_bytes INTEGER NOT NULL,
			token_estimate INTEGER NOT NULL,
			created_at TEXT DEFAULT (datetime('now'))
		);
		CREATE INDEX IF NOT EXISTS idx_context_metrics_session ON context_metrics(session_id);
		CREATE INDEX IF NOT EXISTS idx_context_metrics_command ON context_metrics(command);
		CREATE INDEX IF NOT EXISTS idx_context_metrics_created ON context_metrics(created_at);
	`)
	return err
}

// Log records one command's output size.
func Log(d *sql.DB, sessionID, command string, outputBytes int) error {
	tokens := outputBytes / 4 // rough estimate: 4 bytes per token
	_, err := d.Exec(
		`INSERT INTO context_metrics (session_id, command, output_bytes, token_estimate) VALUES (?, ?, ?, ?)`,
		sessionID, command, outputBytes, tokens,
	)
	return err
}

// Entry is a single metrics row.
type Entry struct {
	ID            int    `json:"id"`
	SessionID     string `json:"session_id"`
	Command       string `json:"command"`
	OutputBytes   int    `json:"output_bytes"`
	TokenEstimate int    `json:"token_estimate"`
	CreatedAt     string `json:"created_at"`
}

// SessionSummary groups metrics by command within a session.
type SessionSummary struct {
	SessionID     string           `json:"session_id"`
	TotalBytes    int              `json:"total_bytes"`
	TotalTokens   int              `json:"total_tokens"`
	CommandCount  int              `json:"command_count"`
	ByCommand     []CommandSummary `json:"by_command"`
	StartedAt     string           `json:"started_at"`
	LastActivity  string           `json:"last_activity"`
}

// CommandSummary is per-command aggregation.
type CommandSummary struct {
	Command       string `json:"command"`
	Calls         int    `json:"calls"`
	TotalBytes    int    `json:"total_bytes"`
	TotalTokens   int    `json:"total_tokens"`
	AvgBytes      int    `json:"avg_bytes"`
	AvgTokens     int    `json:"avg_tokens"`
}

// Recent returns the last N metrics entries.
func Recent(d *sql.DB, limit int) ([]Entry, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := d.Query(
		`SELECT id, session_id, command, output_bytes, token_estimate, created_at
		 FROM context_metrics ORDER BY created_at DESC LIMIT ?`, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var entries []Entry
	for rows.Next() {
		var e Entry
		if err := rows.Scan(&e.ID, &e.SessionID, &e.Command, &e.OutputBytes, &e.TokenEstimate, &e.CreatedAt); err != nil {
			return nil, err
		}
		entries = append(entries, e)
	}
	return entries, rows.Err()
}

// Summary returns aggregated metrics for a session (or all if sessionID is empty).
func Summary(d *sql.DB, sessionID string) (*SessionSummary, error) {
	var query string
	var args []any

	if sessionID != "" {
		query = `SELECT command, COUNT(*) as calls, SUM(output_bytes) as total_bytes, SUM(token_estimate) as total_tokens,
				 MIN(created_at) as started, MAX(created_at) as last_activity
				 FROM context_metrics WHERE session_id = ? GROUP BY command ORDER BY total_tokens DESC`
		args = append(args, sessionID)
	} else {
		query = `SELECT command, COUNT(*) as calls, SUM(output_bytes) as total_bytes, SUM(token_estimate) as total_tokens,
				 MIN(created_at) as started, MAX(created_at) as last_activity
				 FROM context_metrics GROUP BY command ORDER BY total_tokens DESC`
	}

	rows, err := d.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	s := &SessionSummary{SessionID: sessionID}
	for rows.Next() {
		var cs CommandSummary
		var started, lastActivity string
		if err := rows.Scan(&cs.Command, &cs.Calls, &cs.TotalBytes, &cs.TotalTokens, &started, &lastActivity); err != nil {
			return nil, err
		}
		if cs.Calls > 0 {
			cs.AvgBytes = cs.TotalBytes / cs.Calls
			cs.AvgTokens = cs.TotalTokens / cs.Calls
		}
		s.TotalBytes += cs.TotalBytes
		s.TotalTokens += cs.TotalTokens
		s.CommandCount += cs.Calls
		s.ByCommand = append(s.ByCommand, cs)
		if s.StartedAt == "" || started < s.StartedAt {
			s.StartedAt = started
		}
		if lastActivity > s.LastActivity {
			s.LastActivity = lastActivity
		}
	}
	return s, rows.Err()
}

// SessionHistory returns per-session totals.
func SessionHistory(d *sql.DB, limit int) ([]SessionSummary, error) {
	if limit <= 0 {
		limit = 20
	}
	rows, err := d.Query(`
		SELECT session_id, COUNT(*) as cmds, SUM(output_bytes) as bytes, SUM(token_estimate) as tokens,
		       MIN(created_at), MAX(created_at)
		FROM context_metrics
		GROUP BY session_id
		ORDER BY MAX(created_at) DESC
		LIMIT ?`, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var sessions []SessionSummary
	for rows.Next() {
		var s SessionSummary
		if err := rows.Scan(&s.SessionID, &s.CommandCount, &s.TotalBytes, &s.TotalTokens, &s.StartedAt, &s.LastActivity); err != nil {
			return nil, err
		}
		sessions = append(sessions, s)
	}
	return sessions, rows.Err()
}

// CountingWriter wraps a writer and counts bytes written.
type CountingWriter struct {
	w     io.Writer
	mu    sync.Mutex
	count int
}

// NewCountingWriter wraps w.
func NewCountingWriter(w io.Writer) *CountingWriter {
	return &CountingWriter{w: w}
}

func (cw *CountingWriter) Write(p []byte) (int, error) {
	n, err := cw.w.Write(p)
	cw.mu.Lock()
	cw.count += n
	cw.mu.Unlock()
	return n, err
}

// Count returns bytes written so far.
func (cw *CountingWriter) Count() int {
	cw.mu.Lock()
	defer cw.mu.Unlock()
	return cw.count
}

// SessionID returns a session identifier based on the current Claude Code session
// or falls back to a timestamp-based ID.
func SessionID() string {
	// Claude Code sets CLAUDE_SESSION_ID in hooks; check env.
	if sid := os.Getenv("CLAUDE_SESSION_ID"); sid != "" {
		return sid
	}
	// Fall back to date-hour bucket so commands in same hour group together.
	return time.Now().Format("2006-01-02T15")
}

// Budget shows the estimated context budget with CLI's contribution.
type Budget struct {
	CLITokens      int `json:"cli_tokens"`
	EstSkillReads  int `json:"est_skill_reads"`
	EstConversation int `json:"est_conversation"`
	EstTotal       int `json:"est_total"`
	ContextLimit   int `json:"context_limit"`
	UsagePercent   float64 `json:"usage_percent"`
}

// EstimateBudget computes a rough context budget for the current session.
func EstimateBudget(d *sql.DB, sessionID string) (*Budget, error) {
	s, err := Summary(d, sessionID)
	if err != nil {
		return nil, err
	}

	b := &Budget{
		CLITokens:       s.TotalTokens,
		EstSkillReads:   3500,  // ~3-4 skill files read during setup
		EstConversation: 5000,  // conversation overhead estimate
		ContextLimit:    200000,
	}
	b.EstTotal = b.CLITokens + b.EstSkillReads + b.EstConversation
	if b.ContextLimit > 0 {
		b.UsagePercent = float64(b.EstTotal) / float64(b.ContextLimit) * 100
	}
	return b, nil
}

// FormatBytes returns a human-readable byte count.
func FormatBytes(b int) string {
	if b < 1024 {
		return fmt.Sprintf("%d B", b)
	}
	return fmt.Sprintf("%.1f KB", float64(b)/1024)
}

