package cmd

import (
	"fmt"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	nurgesync "github.com/usenurge/nurgesh/internal/sync"
)

var pushCmd = &cobra.Command{
	Use:   "push",
	Short: "Push local state (classifications, learnings, contacts) to Convex",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
